                    .headers()
                    .get("content-type")
                    .and_then(|v| v.to_str().ok())
                    .unwrap_or("");
                if content_type.contains("text/html") {
                    debug!("Browser URL returned HTML (likely auth page), using API URL");
                    asset.url_api.clone()
                } else {
                    asset.url.clone()
                }
            }
            Err(_) => asset.url_api.clone(),
        },

