async fn calculate_file_digest_async(path: &Path) -> Result<String> {
    let mut file = tokio::fs::File::open(path).await?;
    compute_digest(&mut file).await
}

/// Compute the SHA-256 hex digest of data read from `reader`.
pub async fn compute_digest(reader: &mut (impl tokio::io::AsyncRead + Unpin)) -> Result<String> {
    let mut hasher = Sha256::new();
    let mut buffer = [0u8; 8192];
    loop {
        let read = reader.read(&mut buffer).await?;
        if read == 0 {
            break;
        }
        hasher.update(&buffer[..read]);
    }
    Ok(hex::encode(hasher.finalize()))
}

/// Fetch attestation bundles from the GitHub API for `digest` and verify them
/// against `artifact_bytes`.  Returns `Ok(true)` when at least one bundle
/// verifies, `Err(NoAttestations)` when the API returned no bundles for the
/// digest, and `Err(Verification|…)` when bundles exist but none verified.
///
/// This is the per-file counterpart of [`verify_github_attestation_inner`]:
/// instead of computing the artifact's own SHA-256, it uses a pre-computed
/// digest (e.g. of a single file extracted from an archive).
pub async fn verify_github_attestation_for_digest(
    artifact_bytes: &[u8],
    digest: &str,
    owner: &str,
    repo: &str,
    token: Option<&str>,
    signer_workflow: Option<&str>,
    base_url: Option<&str>,
) -> Result<bool> {
    let mut builder = AttestationClient::builder();
    if let Some(token) = token {
        builder = builder.github_token(token);
    }
    if let Some(base_url) = base_url {
        builder = builder.base_url(base_url);
    }
    let client = builder.build()?;
    let attestations = client
        .fetch_attestations(FetchParams {
            owner: owner.to_string(),
            repo: Some(format!("{owner}/{repo}")),
            digest: format!("sha256:{digest}"),
            limit: 30,
            predicate_type: None,
        })
        .await?;

    if attestations.is_empty() {
        return Err(AttestationError::NoAttestations);
    }

    let mut trust_roots = TrustRoots::default();
    verify_attestation_bundles(&attestations, artifact_bytes, signer_workflow, &mut trust_roots)
        .await
}

