+/// Extract an archive into a temporary directory and return the paths of every
+/// regular file it contains.  The returned [`tempfile::TempDir`] must be kept
+/// alive by the caller — dropping it removes the directory.
+///
+/// Only tar-family archives are supported (tar.gz, tar.xz, tar.bz2, tar.zst,
+/// plain tar).  Zip and 7z are not supported and return an error.
+///
+/// This is used for per-file attestation verification: when a GitHub release
+/// attests individual files inside the archive rather than the archive blob,
+/// we need to extract the files to compute their SHA-256 digests.
+pub fn extract_archive_files(
+    archive: &Path,
+    format: TarFormat,
+) -> Result<(tempfile::TempDir, Vec<PathBuf>)> {
+    if !format.is_archive() {
+        bail!(
+            "not an archive format: {}",
+            archive.display()
+        );
+    }
+    if format == TarFormat::Zip || format == TarFormat::SevenZip {
+        bail!(
+            "per-file attestation verification does not support {} archives",
+            format
+        );
+    }
+
+    let tmp = tempfile::tempdir()?;
+    untar(
+        archive,
+        tmp.path(),
+        &TarOptions {
+            format,
+            strip_components: 0,
+            pr: None,
+            preserve_mtime: true,
+        },
+    )?;
+
+    let mut files = Vec::new();
+    for entry in WalkDir::new(tmp.path()).follow_links(false) {
+        let entry = entry?;
+        if entry.file_type().is_file() {
+            files.push(entry.into_path());
+        }
+    }
+    files.sort();
+    Ok((tmp, files))
+}
