/// Try to verify GitHub artifact attestations. Returns:
/// - Ok(true) if attestations exist and verified successfully
/// - Ok(false) if attestations exist but verification failed
/// - Err(NoAttestations) if no attestations found
/// - Err(Error) if an error occurred during verification
///
/// When the archive blob itself has no attestations, falls back to
/// per-file verification: extracts the archive, computes each file's
/// SHA-256, and checks the GitHub attestations API for every file.
/// The fallback succeeds only if *every* regular file in the archive
/// has a valid attestation (fail-closed).
async fn try_verify_github_attestations(
    &self,
    ctx: &InstallContext,
    tv: &ToolVersion,
    file_path: &std::path::Path,
    api_url: &str,
) -> std::result::Result<bool, VerificationStatus> {
    ctx.pr
        .set_message("verify GitHub artifact attestations".to_string());

    // Parse owner/repo from the repo string
    let repo = self.repo();
    let parts: Vec<&str> = repo.split('/').collect();
    if parts.len() != 2 {
        return Err(VerificationStatus::Error(format!(
            "Invalid repo format: {repo}"
        )));
    }
    let (owner, repo_name) = (parts[0], parts[1]);

    match crate::github::sigstore::verify_attestation(
        file_path,
        owner,
        repo_name,
        None, // We don't know the expected workflow
        Some(api_url),
    )
    .await
    {
        Ok(verified) => {
            if verified {
                ctx.pr
                    .set_message("✓ GitHub artifact attestations verified".to_string());
                debug!("GitHub artifact attestations verified successfully for {tv}");
            }
            Ok(verified)
        }
        Err(crate::github::sigstore::AttestationError::NoAttestations) => {
            // No attestations for the archive blob — try per-file attestation.
            self.try_verify_github_attestations_per_file(
                ctx, tv, file_path, api_url, owner, repo_name,
            )
            .await
        }
        Err(e) => Err(VerificationStatus::Error(e.to_string())),
    }
}

/// Per-file attestation fallback.  Extracts the archive, computes the
/// SHA-256 of each regular file, and verifies GitHub attestations for
/// every one.  Succeeds only when every file has a valid attestation.
///
/// Returns `Ok(true)` when all files verified, `Ok(false)` when
/// attestations exist for at least one file but none verified,
/// `Err(NoAttestations)` when no file had any attestations, and
/// `Err(Error)` on extraction or API failures.
async fn try_verify_github_attestations_per_file(
    &self,
    ctx: &InstallContext,
    tv: &ToolVersion,
    file_path: &std::path::Path,
    api_url: &str,
    owner: &str,
    repo_name: &str,
) -> std::result::Result<bool, VerificationStatus> {
    // Detect the archive format.  Non-archives cannot have "files inside"
    // so there is nothing to fall back to.
    let file_name = file_path
        .file_name()
        .unwrap_or_default()
        .to_string_lossy();
    let format = crate::file::TarFormat::from_file_name(&file_name);
    if !format.is_archive() {
        debug!(
            "Per-file attestation fallback skipped: {file_name} is not an archive"
        );
        return Err(VerificationStatus::NoAttestations);
    }

    ctx.pr.set_message(
        "verify GitHub artifact attestations (per-file)".to_string(),
    );
    debug!(
        "No attestations for archive blob, trying per-file attestation for {tv}"
    );

    // Extract to a temp dir and collect all regular file paths.
    let (_tmp, files) = match crate::file::extract_archive_files(file_path, format) {
        Ok(r) => r,
        Err(e) => {
            return Err(VerificationStatus::Error(format!(
                "Failed to extract archive for per-file attestation: {e}"
            )));
        }
    };

    if files.is_empty() {
        debug!("Per-file attestation: archive is empty, nothing to verify");
        return Err(VerificationStatus::NoAttestations);
    }

    // Track whether we saw any attestations across all files.
    let mut any_attestations_found = false;

    for file in &files {
        // Read file bytes and compute digest.
        let file_bytes = match std::fs::read(file) {
            Ok(b) => b,
            Err(e) => {
                return Err(VerificationStatus::Error(format!(
                    "Failed to read {} for per-file attestation: {e}",
                    file.display()
                )));
            }
        };
        let digest = match crate::github::sigstore::compute_digest(
            &mut std::io::Cursor::new(&file_bytes),
        )
        .await
        {
            Ok(d) => d,
            Err(e) => {
                return Err(VerificationStatus::Error(format!(
                    "Failed to compute digest for {}: {e}",
                    file.display()
                )));
            }
        };

        let relative = file
            .strip_prefix(_tmp.path())
            .unwrap_or(file)
            .display();

        match crate::github::sigstore::verify_attestation_for_digest(
            &file_bytes,
            &digest,
            owner,
            repo_name,
            None,
            Some(api_url),
        )
        .await
        {
            Ok(true) => {
                debug!(
                    "Per-file attestation verified for {relative} (digest sha256:{digest})"
                );
                any_attestations_found = true;
            }
            Ok(false) => {
                // Attestations exist for this file's digest but the
                // cryptographic verification failed — hard error.
                return Err(VerificationStatus::Error(format!(
                    "Per-file attestation verification failed for {relative}"
                )));
            }
            Err(crate::github::sigstore::AttestationError::NoAttestations) => {
                // No attestations for this file.  We require ALL files to
                // be attested, so this is a hard failure — but we continue
                // iterating to log diagnostics for every file.
                debug!(
                    "Per-file attestation: no attestations for {relative} \
                     (digest sha256:{digest})"
                );
                return Err(VerificationStatus::Error(format!(
                    "Per-file attestation: file {relative} has no GitHub attestation. \
                     All files in the archive must be attested."
                )));
            }
            Err(e) => {
                return Err(VerificationStatus::Error(format!(
                    "Per-file attestation error for {relative}: {e}"
                )));
            }
        }
    }

    if any_attestations_found {
        ctx.pr.set_message(
            "✓ GitHub artifact attestations verified (per-file)".to_string(),
        );
        debug!(
            "Per-file attestation verified for all {} files in {tv}",
            files.len()
        );
        Ok(true)
    } else {
        // Should be unreachable — if no file had attestations we'd have
        // hit the NoAttestations branch above — but fail closed.
        Err(VerificationStatus::NoAttestations)
    }
}

