+                debug!(
+                    "Per-file attestation verified for {relative} (digest sha256:{digest})"
+                );
+                any_attestations_found = true;
+            }
+            Ok(false) => {
+                // Attestations exist for this file's digest but the
+                // cryptographic verification failed — hard error.
+                return Err(VerificationStatus::Error(format!(
+                    "Per-file attestation verification failed for {relative}"
+                )));
+            }
+            Err(crate::github::sigstore::AttestationError::NoAttestations) => {
+                // No attestations for this file.  We require ALL files to
+                // be attested, so this is a hard failure — but we continue
+                // iterating to log diagnostics for every file.
+                debug!(
+                    "Per-file attestation: no attestations for {relative} \
+                     (digest sha256:{digest})"
+                );
+                return Err(VerificationStatus::Error(format!(
+                    "Per-file attestation: file {relative} has no GitHub attestation. \
+                     All files in the archive must be attested."
+                )));
