/// Compute the SHA-256 hex digest of data read from `reader`.
pub async fn compute_digest(reader: &mut (impl tokio::io::AsyncRead + Unpin)) -> Result<String> {
    let mut hasher = Sha256::new();
    let mut buffer = [0u8; 8192];
    loop {
        let read = reader.read(&mut buffer).await?;
        if read == 0 {
            break;
        }
        hasher.update(&buffer[..read]);
    }
    Ok(hex::encode(hasher.finalize()))
}

