    #[test]
    fn test_extract_archive_files_tar_gz() {
        use flate2::write::GzEncoder;
        use flate2::Compression;

        let dir = tempfile::tempdir().unwrap();
        let archive_path = dir.path().join("test.tar.gz");

        // Create a small tar.gz with two files.
        {
            let tar_file = File::create(&archive_path).unwrap();
            let enc = GzEncoder::new(tar_file, Compression::fast());
            let mut tar = tar::Builder::new(enc);
            let mut header = tar::Header::new_gnu();
            let data_a = b"contents of a";
            header.set_size(data_a.len() as u64);
            header.set_mode(0o644);
            header.set_cksum();
            tar.append_data(&mut header, "dir/a.txt", &data_a[..])
                .unwrap();
            let mut header = tar::Header::new_gnu();
            let data_b = b"contents of b";
            header.set_size(data_b.len() as u64);
            header.set_mode(0o644);
            header.set_cksum();
            tar.append_data(&mut header, "dir/b.txt", &data_b[..])
                .unwrap();
            tar.finish().unwrap();
        }

        let (_tmp, files) = extract_archive_files(&archive_path, TarFormat::TarGz).unwrap();
        assert_eq!(files.len(), 2, "expected two regular files");

        let names: Vec<String> = files
            .iter()
            .map(|p| {
                p.strip_prefix(_tmp.path())
                    .unwrap_or(p)
                    .to_string_lossy()
                    .to_string()
            })
            .collect();
        assert!(names.contains(&"dir/a.txt".to_string()));
        assert!(names.contains(&"dir/b.txt".to_string()));
    }

    #[test]
    fn test_extract_archive_files_rejects_non_archive() {
        let dir = tempfile::tempdir().unwrap();
        let raw = dir.path().join("tool.bin");
        std::fs::write(&raw, b"hello").unwrap();
        let err = extract_archive_files(&raw, TarFormat::Raw).unwrap_err();
        assert!(err.to_string().contains("not an archive"));
    }

    #[test]
    fn test_extract_archive_files_rejects_zip() {
        let dir = tempfile::tempdir().unwrap();
        let zip_path = dir.path().join("test.zip");
        std::fs::write(&zip_path, b"PK\x03\x04fake").unwrap();
        let err = extract_archive_files(&zip_path, TarFormat::Zip).unwrap_err();
        assert!(err.to_string().contains("does not support"));
    }
}

