    #[test]
    fn test_extract_archive_files_for_per_file_attestation() {
        use flate2::write::GzEncoder;
        use flate2::Compression;
        use std::io::Write;

        let dir = tempfile::tempdir().unwrap();
        let archive_path = dir.path().join("tool-1.0.0-linux-x86_64.tar.gz");

        // Create a tar.gz with two regular files.
        {
            let tar_file = std::fs::File::create(&archive_path).unwrap();
            let enc = GzEncoder::new(tar_file, Compression::fast());
            let mut tar = tar::Builder::new(enc);
            let mut header = tar::Header::new_gnu();
            let data = b"#!/bin/sh\necho hello";
            header.set_size(data.len() as u64);
            header.set_mode(0o755);
            header.set_cksum();
            tar.append_data(&mut header, "bin/tool", &data[..])
                .unwrap();
            let mut header = tar::Header::new_gnu();
            let license = b"MIT License";
            header.set_size(license.len() as u64);
            header.set_mode(0o644);
            header.set_cksum();
            tar.append_data(&mut header, "LICENSE", &license[..])
                .unwrap();
            tar.finish().unwrap();
        }

        let format = crate::file::TarFormat::from_file_name("tool-1.0.0-linux-x86_64.tar.gz");
        assert!(format.is_archive());
        let (tmp, files) = crate::file::extract_archive_files(&archive_path, format).unwrap();
        assert_eq!(files.len(), 2, "expected two regular files in archive");

        // All extracted files must be readable.
        for f in &files {
            assert!(f.is_file());
            let _ = std::fs::read(f).unwrap();
        }

        // Temp dir is still alive because `tmp` is in scope.
        for f in &files {
            assert!(f.exists());
        }
        drop(tmp);
        // After dropping, the directory is removed.
        for f in &files {
            assert!(!f.exists());
        }
    }

    #[test]
    fn test_per_file_skips_non_archive() {
        // A raw binary (not an archive) should not trigger per-file extraction.
        let format = crate::file::TarFormat::from_file_name("tool-1.0.0-linux-x86_64.bin");
        assert!(!format.is_archive());
        // extract_archive_files rejects non-archives.
        let dir = tempfile::tempdir().unwrap();
        let raw = dir.path().join("tool-1.0.0-linux-x86_64.bin");
        std::fs::write(&raw, b"binary").unwrap();
        let err = crate::file::extract_archive_files(&raw, format).unwrap_err();
        assert!(err.to_string().contains("not an archive"));
    }

    #[test]
    fn test_per_file_empty_archive() {
        use flate2::write::GzEncoder;
        use flate2::Compression;

        let dir = tempfile::tempdir().unwrap();
        let archive_path = dir.path().join("empty.tar.gz");
        {
            let tar_file = std::fs::File::create(&archive_path).unwrap();
            let enc = GzEncoder::new(tar_file, Compression::fast());
            let mut tar = tar::Builder::new(enc);
            tar.finish().unwrap();
        }

        let format = crate::file::TarFormat::from_file_name("empty.tar.gz");
        let (_tmp, files) = crate::file::extract_archive_files(&archive_path, format).unwrap();
        assert!(
            files.is_empty(),
            "empty archive should yield zero files"
        );
    }
}

