#[tokio::test]
async fn verify_for_digest_returns_no_attestations_for_unknown_digest() {
    // Build a client pointing at a non-existent local endpoint so the test
    // is fully offline.  We only exercise the "API returns empty" path.
    let digest = hex::encode(Sha256::digest(b"nonexistent-artifact-12345"));
    // Use a bogus base_url so the HTTP request fails immediately — the
    // function should surface that as an Http error, not succeed.
    let err = verify_github_attestation_for_digest(
        b"nonexistent-artifact-12345",
        &digest,
        "actions",
        "toolkit",
        None,
        None,
        Some("http://127.0.0.1:1"),
    )
    .await
    .unwrap_err();
    // The important thing is that it fails (doesn't silently succeed).
    assert!(
        matches!(err, AttestationError::Http(_) | AttestationError::Api(_)),
        "expected Http or Api error, got {err:?}"
    );
}

